module temperature_sensor_controller (
    input [9:0] temp_in,
    input enable,
    input reset,
    output reg obf_alert
);

    always @(posedge enable or posedge reset) begin
        if (reset) begin
            obf_alert <= 0;
        end else begin
            if (temp_in > 10'd75) begin
                obf_alert <= 1;
            end else if (temp_in < 10'd60) begin
                obf_alert <= 0;
            end
            // If temp_in is between 60 and 75, obf_alert remains unchanged
        end
    end
endmodule
